#include "MazeGenerator.h"\n#include <iostream>\n#include <vector>\n#include <algorithm>\n#include <stdexcept>\n#include <random>\n\nMazeGenerator::MazeGenerator(int r, int c)  \n    : rows(r), cols(c), rng(std::random_device{}()) {\n    if (r <= 0 || c <= 0) {\n        throw std::invalid_argument("Rows and columns must be positive integers");\n    }\n    maze.resize(2 * rows + 1, std::vector<char>(2 * cols + 1, '#'));\n}\n\nvoid MazeGenerator::dfs(int x, int y) {\n    int dx[] = {0, 0, 2, -2};\n    int dy[] = {2, -2, 0, 0};\n    std::vector<int> dir = {0, 1, 2, 3};\n    std::shuffle(dir.begin(), dir.end(), rng);\n\n    for (int i : dir) {\n        int nx = x + dx[i], ny = y + dy[i];\n        if (nx > 0 && ny > 0 && nx < 2 * rows && ny < 2 * cols && maze[nx][ny] == '#') {\n            maze[nx][ny] = ' ';\n            maze[x + dx[i] / 2][y + dy[i] / 2] = ' ';\n            dfs(nx, ny);\n        }\n    }\n}\n\nvoid MazeGenerator::generateMaze() {\n    maze[1][1] = ' ';\n    dfs(1, 1);\n    maze[0][1] = 'S';\n    if (2 * rows < static_cast<int>(maze.size()) &&  \n        2 * cols - 1 < static_cast<int>(maze[0].size())) {\n        maze[2 * rows][2 * cols - 1] = 'E';\n    }\n}\n\nvoid MazeGenerator::printMaze() {\n    for (const auto& row : maze) {\n        for (char cell : row) {\n            std::cout << cell;\n        }\n        std::cout << '\\n';\n    }\n}\n\nconst std::vector<std::vector<char>>& MazeGenerator::getMaze() const {\n    return maze;\n}